mapper.select:
SELECT TIME as time, DEV_NAME as devName, ROUND(avgMerge(UTILIZATION_AVG),2) as utilization, ROUND(avgMerge(SIZE_AVG),2) as size, ROUND(avgMerge(IO_STAT_AVG),2) as ioStat, ROUND(avgMerge(RD_STAT_AVG),2) as rdStat, ROUND(avgMerge(WR_STAT_AVG),2) as wrStat, ROUND(avgMerge(RD_REQ_AVG),2) as rdReq, ROUND(avgMerge(WR_REQ_AVG),2) as wrReq, ROUND(avgMerge(RD_REQ_PS_AVG),2) as rdReqps, ROUND(avgMerge(WR_REQ_PS_AVG),2) as wrReqps, ROUND(avgMerge(RD_LATENCY_AVG),2) as rdLatency, ROUND(avgMerge(WR_LATENCY_AVG),2) as wrLatency FROM AGG_DOMAIN_IO_STAT_30M WHERE TIME BETWEEN ${startTime} AND ${endTime} AND DOMAIN_ID=${domainId}
AND DEV_NAME = #{currentDisk}
AND DEV_NAME IN (select DEV_NAME from TBL_DOMAIN_IO_STAT t1 WHERE t1.TIME = (select MAX(TIME)-${duration} from TBL_DOMAIN_IO_STAT WHERE DOMAIN_ID=${domainId}) and t1.DOMAIN_ID=${domainId}) GROUP BY TIME, DEV_NAME ORDER BY TIME ASC

SELECT IO.DOMAIN_ID as domainId,
ROUND(sum(IO_STAT_AVG * if((${endTime} - toUnixTimestamp(TIME)) > 1800, 1800, ${endTime} - toUnixTimestamp(TIME))),2) as sumIoStat,
TD.title as title FROM
(SELECT DOMAIN_ID, DEV_NAME, TIME, avgMerge(IO_STAT_AVG) as IO_STAT_AVG FROM AGG_DOMAIN_IO_STAT_30M
WHERE TIME BETWEEN ${startTime} AND ${endTime}

    AND HOST_POOL_ID =${hostPoolId}


    AND CLUSTER_ID =${clusterId}


    AND HOST_ID =${hostId}


    AND OP_GROUP_CODE LIKE #{operatorGroupCode}

GROUP BY DOMAIN_ID, DEV_NAME, TIME)  IO,
${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_DOMAIN} TD WHERE IO.DOMAIN_ID=TD.id
GROUP BY DOMAIN_ID,TD.title ORDER BY sumIoStat DESC

    LIMIT 0,${limit}

SELECT DOMAIN_ID as domainId, DEV_NAME as devName,
ROUND(avgMerge(UTILIZATION_AVG),2) as avgUtilization, maxMerge(UTILIZATION_MAX) as maxUtilization, minMerge(UTILIZATION_MIN) as minUtilization
FROM AGG_DOMAIN_IO_STAT_30M detail  WHERE TIME BETWEEN ${startTime} AND ${endTime}

    AND DOMAIN_ID = ${domainId}


    AND DOMAIN_ID in (${vmIds})

GROUP BY DOMAIN_ID, DEV_NAME
